sql:
SELECT COUNT(conversion_id) AS signup_count
FROM conversion_events
WHERE conversion_type = 'signup';

SELECT conversion_type, AVG(conversion_value) AS average_conversion_value
FROM conversion_events
GROUP BY conversion_type;

SELECT tag_id, COUNT(assignment_id) AS assignment_count
FROM tag_assignments
GROUP BY tag_id;

external_knowledge:
- "prolonged sessions" refers to sessions longer than the average session duration; 
- "intense interaction" is measured by the II (Interaction Index) metric; 
- "most engagement" is determined by the highest total II metric across a user's sessions;
- "engagement levels" are measured by the cumulative II metric.

sql:
SELECT conversion_type, conversion_value, conversion_time
FROM conversion_events
ORDER BY conversion_value DESC;

SELECT conversion_id, conversion_type, conversion_value, conversion_time
FROM conversion_events
WHERE user_id = 1;
